import { Component, Prop, h, Event, EventEmitter, Element, Watch } from '@stencil/core';

@Component({
  tag: 'sheet-component',
  styleUrl: 'sheet-component.css',
  shadow: true,
})
export class SheetComponent {
  @Prop({ mutable: true, reflect: true }) open: boolean = false;
  @Event() sheetClosed: EventEmitter<void>;

  @Element() el: HTMLElement;

  private handleOverlayClick = (e: MouseEvent) => {
    // Only close if overlay (not sheet) is clicked
    if ((e.target as HTMLElement).classList.contains('sheet-overlay')) {
      this.close();
    }
  };

  private close = () => {
    this.open = false;
    this.sheetClosed.emit();
  };

  @Watch('open')
  onOpenChange(newV: boolean) {
    document.body.classList.toggle('sheet-component-open', newV);
  }

  disconnectedCallback() {
    document.body.classList.remove('sheet-component-open');
  }

  render() {
    return (
      <div
        class={{
          'sheet-overlay': true,
          'active': this.open,
        }}
        onClick={this.handleOverlayClick}
        aria-hidden={!this.open}
      >
        <div
          class={{
            'sheet': true,
            'sheet--open': this.open
          }}
          tabindex="-1"
        >
          <slot></slot>
        </div>
      </div>
    );
  }
}


